import { useState, useEffect } from 'react'
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Button,
  Alert,
  CircularProgress,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  Box,
  OutlinedInput,
  Typography
} from '@mui/material'
import { userRequest } from '../requestMethods'

const ITEM_HEIGHT = 48
const ITEM_PADDING_TOP = 8
const MenuProps = {
  PaperProps: {
    style: {
      maxHeight: ITEM_HEIGHT * 4.5 + ITEM_PADDING_TOP,
      width: 250,
    },
  },
}

const CreateProjectModal = ({ open, onClose, onProjectCreated }) => {
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    memberIds: []  // Array of user IDs to add as members
  })
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)
  const [users, setUsers] = useState([])
  const [fetchingUsers, setFetchingUsers] = useState(false)

  useEffect(() => {
    if (open) {
      fetchUsers()
    }
  }, [open])

  const fetchUsers = async () => {
    try {
      setFetchingUsers(true)
      const res = await userRequest.get('/users')
      setUsers(res.data)
    } catch (err) {
      console.error('Failed to fetch users:', err)
      setUsers([])
    } finally {
      setFetchingUsers(false)
    }
  }

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    })
  }

  const handleMemberChange = (event) => {
    const { value } = event.target
    setFormData({
      ...formData,
      memberIds: typeof value === 'string' ? value.split(',') : value
    })
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')
    setLoading(true)

    try {
      const projectRes = await userRequest.post('/projects', {
        name: formData.name,
        description: formData.description
      })
      
      const newProject = projectRes.data
      
      // Then, add selected members to the project
      if (formData.memberIds.length > 0) {
        const memberPromises = formData.memberIds.map(userId =>
          userRequest.post(`/projects/${newProject._id}/members`, {
            userId,
            role: 'member'
          })
        )
        
        await Promise.all(memberPromises)
      }
      
      // Notify parent component about new project
      if (onProjectCreated) {
        onProjectCreated(newProject)
      }
      
      setFormData({ name: '', description: '', memberIds: [] })
      onClose()
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create project')
    } finally {
      setLoading(false)
    }
  }

  const handleClose = () => {
    setFormData({ name: '', description: '', memberIds: [] })
    setError('')
    onClose()
  }

  return (
    <Dialog 
      open={open} 
      onClose={handleClose}
      maxWidth="sm"
      fullWidth
    >
      <DialogTitle sx={{ fontWeight: 600 }}>
        Create New Project
      </DialogTitle>
      
      <form onSubmit={handleSubmit}>
        <DialogContent>
          {error && (
            <Alert severity="error" sx={{ mb: 2 }}>
              {error}
            </Alert>
          )}
          
          <TextField
            name="name"
            label="Project Name"
            fullWidth
            required
            value={formData.name}
            onChange={handleChange}
            sx={{ mb: 2 }}
            placeholder="Enter project name"
            autoFocus
          />
          
          <TextField
            name="description"
            label="Description"
            fullWidth
            multiline
            rows={3}
            value={formData.description}
            onChange={handleChange}
            sx={{ mb: 2 }}
            placeholder="Enter project description (optional)"
          />
          
          <FormControl fullWidth sx={{ mb: 2 }}>
            <InputLabel id="members-label">Team Members</InputLabel>
            <Select
              labelId="members-label"
              multiple
              name="memberIds"
              value={formData.memberIds}
              onChange={handleMemberChange}
              input={<OutlinedInput label="Team Members" />}
              renderValue={(selected) => (
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5 }}>
                  {selected.map((userId) => {
                    const user = users.find(u => u._id === userId)
                    return (
                      <Chip 
                        key={userId} 
                        label={user?.fullName || user?.email || userId} 
                        size="small"
                      />
                    )
                  })}
                </Box>
              )}
              MenuProps={MenuProps}
            >
              {fetchingUsers ? (
                <MenuItem disabled>
                  <CircularProgress size={20} sx={{ mr: 1 }} />
                  Loading users...
                </MenuItem>
              ) : users.length === 0 ? (
                <MenuItem disabled>
                  No users available
                </MenuItem>
              ) : (
                users.map((user) => (
                  <MenuItem key={user._id} value={user._id}>
                    <Box sx={{ display: 'flex', flexDirection: 'column' }}>
                      <Typography variant="body2">{user.fullName}</Typography>
                      <Typography variant="caption" color="text.secondary">
                        {user.email}
                      </Typography>
                    </Box>
                  </MenuItem>
                ))
              )}
            </Select>
          </FormControl>
          
          <Typography variant="caption" color="text.secondary">
            You will be automatically added as project admin. Selected members can be managed later.
          </Typography>
        </DialogContent>
        
        <DialogActions sx={{ px: 3, pb: 2 }}>
          <Button 
            onClick={handleClose}
            disabled={loading}
          >
            Cancel
          </Button>
          <Button 
            type="submit" 
            variant="contained"
            disabled={loading || !formData.name.trim()}
          >
            {loading ? <CircularProgress size={24} /> : 'Create Project'}
          </Button>
        </DialogActions>
      </form>
    </Dialog>
  )
}

export default CreateProjectModal