import { useEffect, useState } from 'react'
import { useSelector } from 'react-redux'
import { useNavigate } from 'react-router-dom'
import { 
  Container, Typography, Button, Paper, Box, Alert, 
  Divider, Grid, Chip, LinearProgress, CircularProgress 
} from '@mui/material'
import Navbar from '../components/Navbar'
import Footer from '../components/Footer'
import CreateProjectModal from '../components/CreateProjectModal'
import {
  Folder as FolderIcon,
  People as PeopleIcon,
  Schedule as ScheduleIcon,
  Task as TaskIcon
} from '@mui/icons-material'
import { userRequest } from '../requestMethods'

const Dashboard = () => {
  const navigate = useNavigate()
  const { currentUser } = useSelector(state => state.user)
  
  const [projects, setProjects] = useState([])
  const [myTasks, setMyTasks] = useState([])
  const [projectProgress, setProjectProgress] = useState([])
  const [stats, setStats] = useState({
    totalTasks: 0,
    completed: 0,
    inProgress: 0,
    overdue: 0
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  
  // Modal state
  const [createProjectOpen, setCreateProjectOpen] = useState(false)

  useEffect(() => {
    fetchDashboardData()
  }, [])

  const fetchDashboardData = async () => {
    try {
      setLoading(true)
      setError('')
      
      const [projectsRes] = await Promise.all([
        userRequest.get('/projects')
      ])
      
      const projectsData = projectsRes.data
      setProjects(projectsData)
      
      let totalTasks = 0
      let completed = 0
      let inProgress = 0
      let overdue = 0
      let allMyTasks = []
      
      const projectProgressData = await Promise.all(
        projectsData.map(async (project) => {
          try {
            const tasksRes = await userRequest.get(`/tasks/${project._id}`)
            const tasks = tasksRes.data
            
            totalTasks += tasks.length
            completed += tasks.filter(t => t.status === 'done').length
            inProgress += tasks.filter(t => t.status === 'in_progress').length
            overdue += tasks.filter(t => 
              t.dueDate && new Date(t.dueDate) < new Date() && t.status !== 'done'
            ).length
            
            const myProjectTasks = tasks.filter(t => 
              t.assignedTo?._id === currentUser?._id || 
              t.assignedTo === currentUser?._id
            )
            allMyTasks = [...allMyTasks, ...myProjectTasks]
            
            return {
              _id: project._id,
              name: project.name,
              totalTasks: tasks.length,
              completedTasks: tasks.filter(t => t.status === 'done').length,
              progress: tasks.length > 0 
                ? Math.round((tasks.filter(t => t.status === 'done').length / tasks.length) * 100)
                : 0,
              members: project.members?.length || 0
            }
          } catch (err) {
            return {
              _id: project._id,
              name: project.name,
              totalTasks: project.taskStats?.total || 0,
              completedTasks: project.taskStats?.completed || 0,
              progress: project.taskStats?.total > 0 
                ? Math.round((project.taskStats.completed / project.taskStats.total) * 100)
                : 0,
              members: project.members?.length || 0
            }
          }
        })
      )
      
      setStats({ totalTasks, completed, inProgress, overdue })
      setMyTasks(allMyTasks.filter(t => t.status !== 'done').slice(0, 10))
      setProjectProgress(projectProgressData)
      
    } catch (err) {
      console.error('Dashboard fetch error:', err)
      setError(err.response?.data?.message || 'Failed to load dashboard data')
    } finally {
      setLoading(false)
    }
  }

  const handleProjectCreated = (newProject) => {
    setProjects(prev => [newProject, ...prev])
  }

  if (loading) {
    return (
      <>
        <Navbar />
        <Container sx={{ mt: '100px', display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
          <CircularProgress />
        </Container>
        <Footer />
      </>
    )
  }

  return (
    <>
      <Navbar />
      <Container sx={{ mt: '100px' }}>
        <Typography variant='h4'>
          Welcome {currentUser?.fullName?.split(' ')[0]}
        </Typography>

        {error && (
          <Alert severity="error" sx={{ mt: 2 }} onClose={() => setError('')}>
            {error}
          </Alert>
        )}

        {currentUser?.isAdmin && (
          <Button 
            variant='outlined' 
            sx={{ my: 3 }}
            onClick={() => setCreateProjectOpen(true)}
          >
            Create new project
          </Button>
        )}
        
        <Grid container spacing={2}>
          <Grid size={{xs: 12, md: 3}}>
            <Alert variant="filled" severity="info">
              {stats.totalTasks} total tasks
            </Alert>
          </Grid>
          <Grid size={{xs: 12, md: 3}}>
            <Alert variant="filled" severity="success">
              {stats.completed} done
            </Alert>
          </Grid>
          <Grid size={{xs: 12, md: 3}}>
            <Alert variant="filled" severity="warning">
              {stats.inProgress} in progress
            </Alert>
          </Grid>
          <Grid size={{xs: 12, md: 3}}>
            <Alert variant="filled" severity="error">
              {stats.overdue} overdue
            </Alert>
          </Grid>
        </Grid>

        <Grid container spacing={2} sx={{ my: 3 }}>
          {/* My Tasks Section */}
          <Grid size={{xs: 12, md: 6}}>
            <Paper sx={{ p: 2, height: 500, display: 'flex', flexDirection: 'column' }}>
              <Typography variant='h5'>My Tasks</Typography>
              <Divider sx={{ my: 2 }} />
              
              {myTasks && myTasks.length > 0 ? (
                <Box sx={{ 
                  display: 'flex', 
                  flexDirection: 'column', 
                  gap: 1.5, 
                  overflowY: 'auto',
                  flex: 1,
                  pr: 1,
                  '&::-webkit-scrollbar': {
                    width: 6,
                  },
                  '&::-webkit-scrollbar-track': {
                    bgcolor: 'grey.100',
                    borderRadius: 3,
                  },
                  '&::-webkit-scrollbar-thumb': {
                    bgcolor: 'grey.400',
                    borderRadius: 3,
                    '&:hover': {
                      bgcolor: 'grey.500',
                    },
                  },
                }}>
                  {myTasks.map((task) => (
                    <Paper
                      key={task._id}
                      elevation={0}
                      sx={{
                        p: 1.5,
                        borderLeft: 4,
                        borderColor: 
                          task.priority === 'high' ? 'error.main' :
                          task.priority === 'medium' ? 'warning.main' : 'success.main',
                        bgcolor: 'grey.50',
                        cursor: 'pointer',
                        transition: 'all 0.2s',
                        flexShrink: 0,
                        '&:hover': {
                          bgcolor: 'grey.100',
                          transform: 'translateX(4px)'
                        }
                      }}
                      onClick={() => navigate(`/projects/${task.project?._id || task.project}`)}
                    >
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                        <Box>
                          <Typography variant='subtitle2' sx={{ fontWeight: 600 }}>
                            {task.title}
                          </Typography>
                          <Typography variant='caption' color='text.secondary'>
                            {task.project?.name || 'Unknown Project'}
                          </Typography>
                        </Box>
                        <Chip
                          label={task.status.replace('_', ' ')}
                          size='small'
                          color={
                            task.status === 'done' ? 'success' :
                            task.status === 'in_progress' ? 'warning' :
                            task.status === 'review' ? 'secondary' : 'info'
                          }
                          variant='outlined'
                        />
                      </Box>
                      
                      {task.dueDate && (
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mt: 0.5 }}>
                          <ScheduleIcon sx={{ fontSize: 14, color: 'text.secondary' }} />
                          <Typography variant='caption' color='text.secondary'>
                            Due: {new Date(task.dueDate).toLocaleDateString('en-US', {
                              month: 'short',
                              day: 'numeric',
                              year: 'numeric'
                            })}
                          </Typography>
                          {new Date(task.dueDate) < new Date() && task.status !== 'done' && (
                            <Chip
                              label='Overdue'
                              size='small'
                              color='error'
                              sx={{ height: 20, fontSize: '0.7rem' }}
                            />
                          )}
                        </Box>
                      )}
                    </Paper>
                  ))}
                </Box>
              ) : (
                <Box sx={{ textAlign: 'center', py: 4, flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center' }}>
                  <TaskIcon sx={{ fontSize: 48, color: 'grey.300', mb: 1 }} />
                  <Typography color='text.secondary'>
                    No pending tasks. Great job! 🎉
                  </Typography>
                </Box>
              )}
            </Paper>
          </Grid>

          {/* Project Progress Section */}
          <Grid size={{xs: 12, md: 6}}>
            <Paper sx={{ p: 2, height: 500, display: 'flex', flexDirection: 'column' }}>
              <Typography variant='h5'>Project Progress</Typography>
              <Divider sx={{ my: 2 }} />
              
              {projectProgress && projectProgress.length > 0 ? (
                <Box sx={{ 
                  display: 'flex', 
                  flexDirection: 'column', 
                  gap: 1.5, 
                  overflowY: 'auto',
                  flex: 1,
                  pr: 1,
                  '&::-webkit-scrollbar': {
                    width: 6,
                  },
                  '&::-webkit-scrollbar-track': {
                    bgcolor: 'grey.100',
                    borderRadius: 3,
                  },
                  '&::-webkit-scrollbar-thumb': {
                    bgcolor: 'grey.400',
                    borderRadius: 3,
                    '&:hover': {
                      bgcolor: 'grey.500',
                    },
                  },
                }}>
                  {projectProgress.map((project) => (
                    <Paper
                      key={project._id}
                      elevation={0}
                      sx={{
                        p: 1.5,
                        border: 1,
                        borderColor: 'grey.200',
                        cursor: 'pointer',
                        transition: 'all 0.2s',
                        flexShrink: 0,
                        '&:hover': {
                          borderColor: 'primary.main',
                          boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
                        }
                      }}
                      onClick={() => navigate(`/projects/${project._id}`)}
                    >
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                        <Typography variant='subtitle2' sx={{ fontWeight: 600 }}>
                          {project.name}
                        </Typography>
                        <Chip
                          icon={<PeopleIcon />}
                          label={project.members || 0}
                          size='small'
                          variant='outlined'
                        />
                      </Box>
                      
                      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <Box sx={{ flex: 1 }}>
                          <LinearProgress
                            variant='determinate'
                            value={project.progress || 0}
                            sx={{
                              height: 8,
                              borderRadius: 4,
                              bgcolor: 'grey.200',
                              '& .MuiLinearProgress-bar': {
                                borderRadius: 4,
                                bgcolor: 
                                  (project.progress || 0) === 100 ? 'success.main' :
                                  (project.progress || 0) > 50 ? 'primary.main' : 'warning.main'
                              }
                            }}
                          />
                        </Box>
                        <Typography variant='body2' color='text.secondary' sx={{ minWidth: 45, textAlign: 'right' }}>
                          {project.progress || 0}%
                        </Typography>
                      </Box>
                      
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 0.5 }}>
                        <Typography variant='caption' color='text.secondary'>
                          {project.completedTasks || 0}/{project.totalTasks || 0} tasks completed
                        </Typography>
                        
                        {project.totalTasks > 0 && project.completedTasks === project.totalTasks && (
                          <Chip
                            label='Completed'
                            size='small'
                            color='success'
                            sx={{ height: 20, fontSize: '0.7rem' }}
                          />
                        )}
                      </Box>
                    </Paper>
                  ))}
                </Box>
              ) : (
                <Box sx={{ textAlign: 'center', py: 4, flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center' }}>
                  <FolderIcon sx={{ fontSize: 48, color: 'grey.300', mb: 1 }} />
                  <Typography color='text.secondary'>
                    No projects yet. Create one to get started!
                  </Typography>
                </Box>
              )}
            </Paper>
          </Grid>
        </Grid>
      </Container>
      
      {/* Create Project Modal */}
      <CreateProjectModal 
        open={createProjectOpen}
        onClose={() => setCreateProjectOpen(false)}
        onProjectCreated={handleProjectCreated}
      />
      
      <Footer />
    </>
  )
}

export default Dashboard